"use strict";var xwebdav=new function(){this.select=function(linkType,onSuccess){angular.element("#xwebdav-dialog-controller").scope().select(linkType,onSuccess)};this.insertSaveButton=function(targetId,mimeId,filename,url){$("#"+targetId).append($("<div>").attr("href","javascript:void(0)").addClass("xwebdav-save-button xcloud-save-button").append($("<div>").addClass("image").css("background-image","url('plugins/xwebdav/assets/images/save.png')")).append($("<div>").addClass("text").text(rcmail.gettext("save"))).click(function(){angular.element("#xwebdav-dialog-controller").scope().save(mimeId,filename)}))};this.createSharedUrl=function(){var urlInput=$("#xwebdav_url");if(!urlInput.val()){alert(rcmail.gettext("xwebdav.specify_webdav_url"));return}var url=new URL(urlInput.val());$("#xwebdav_shared_url").val(url.protocol+"//"+url.hostname+"/ocs/v2.php/apps/files_sharing/api/v1/shares")}};